class Solution:
    def wordBreak(self, s: str, wordDict: list[str]) -> bool:
        n = len(s)
        word_set = set(wordDict)

        # dp[i] will be True if s[0...i-1] can be segmented
        dp = [False] * (n + 1)
        dp[0] = True  # An empty string can always be segmented

        for i in range(1, n + 1):
            for j in range(i):
                # If s[0...j-1] can be segmented (dp[j] is True)
                # AND the substring s[j...i-1] is in the word dictionary
                if dp[j] and s[j:i] in word_set:
                    dp[i] = True
                    break  # Found a way to segment s[0...i-1], move to next i

        return dp[n]
